class ASTNode:
    def __init__(self, type, value=None, op=None, left=None, right=None, operand=None):
        self.type = type  # 'number', 'binop', 'unary'
        self.value = value  # for numbers
        self.op = op  # for operators
        self.left = left  # for binop
        self.right = right  # for binop
        self.operand = operand  # for unary


def parse(expression):
    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    # Remove whitespace
    expression = expression.replace(" ", "")

    def tokenize(expr):
        tokens = []
        i = 0
        while i < len(expr):
            if expr[i].isdigit() or expr[i] == ".":
                # Parse number
                num = ""
                while i < len(expr) and (expr[i].isdigit() or expr[i] == "."):
                    num += expr[i]
                    i += 1
                tokens.append(("NUMBER", float(num)))
            elif expr[i] in "+-*/()":
                tokens.append(("OPERATOR", expr[i]))
                i += 1
            else:
                raise ValueError(f"Invalid character: {expr[i]}")
        return tokens

    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("Invalid expression")

    # Parser using recursive descent
    pos = [0]  # Use list to allow modification in nested functions

    def parse_expression():
        return parse_addition()

    def parse_addition():
        left = parse_multiplication()
        if pos[0] < len(tokens) and tokens[pos[0]][1] in "+-":
            op = tokens[pos[0]][1]
            pos[0] += 1
            right = parse_addition()
            return ASTNode("binop", op=op, left=left, right=right)
        return left

    def parse_multiplication():
        left = parse_unary()
        if pos[0] < len(tokens) and tokens[pos[0]][1] in "*/":
            op = tokens[pos[0]][1]
            pos[0] += 1
            right = parse_multiplication()
            return ASTNode("binop", op=op, left=left, right=right)
        return left

    def parse_unary():
        if pos[0] < len(tokens) and tokens[pos[0]][1] == "-":
            pos[0] += 1
            operand = parse_unary()
            return ASTNode("unary", op="-", operand=operand)
        return parse_primary()

    def parse_primary():
        if pos[0] >= len(tokens):
            raise ValueError("Unexpected end of expression")

        token_type, token_value = tokens[pos[0]]

        if token_type == "NUMBER":
            pos[0] += 1
            return ASTNode("number", value=token_value)
        elif token_type == "OPERATOR" and token_value == "(":
            pos[0] += 1
            expr = parse_expression()
            if pos[0] >= len(tokens) or tokens[pos[0]][1] != ")":
                raise ValueError("Unmatched parenthesis")
            pos[0] += 1
            return expr
        else:
            raise ValueError("Unexpected token")

    # Parse the expression
    result = parse_expression()

    # Check if we consumed all tokens
    if pos[0] != len(tokens):
        raise ValueError("Invalid expression")

    return result


def evaluate(node):
    if node.type == "number":
        return node.value
    elif node.type == "binop":
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)
        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == "unary":
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
    raise ValueError("Invalid AST node")
